// Ripristino una tantum: alcuni prodotti hanno perso la categoria (per un bug
// nel form admin che inviava category_id come numero invece che come testo,
// azzerandola a NULL e facendoli sparire dal menu pubblico) e/o le loro
// varianti di formato e scelte obbligatorie (prezzi_json/options_json/
// multi_options_json), azzerate perché il form non le includeva nel
// salvataggio. Entrambi i bug sono risolti nel codice: questo endpoint
// ripara SOLO i prodotti già danneggiati, confrontandoli con i dati
// originali del menu — senza toccare nome, descrizione, foto, prezzo base o
// stato attivo, che restano quelli attuali.
const ADMIN_COOKIE = 'nfarinati_admin_session';

async function verifySession(request, secret) {
  const cookieHeader = request.headers.get('Cookie') || '';
  const match = cookieHeader.match(new RegExp(`(?:^|;\\s*)${ADMIN_COOKIE}=([^;]+)`));
  if (!match) return false;
  const token = decodeURIComponent(match[1]);
  const lastDot = token.lastIndexOf('.');
  if (lastDot === -1) return false;
  const payload = token.substring(0, lastDot);
  const sig = token.substring(lastDot + 1);
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey('raw', encoder.encode(secret), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']);
  const expectedSig = await crypto.subtle.sign('HMAC', key, encoder.encode(payload));
  const expectedHex = [...new Uint8Array(expectedSig)].map(b => b.toString(16).padStart(2, '0')).join('');
  return expectedHex === sig;
}

