function looksWiped(prod) {
  let prezzi = [];
  try { prezzi = JSON.parse(prod.prezzi_json || '[]'); } catch (e) {}
  const hasVariants = prezzi.length > 1 && prezzi.some(p => p.variante);
  const optionsEmpty = (prod.options_json || '{}').trim() === '{}';
  const multiEmpty = (prod.multi_options_json || '{}').trim() === '{}';
  return !hasVariants && optionsEmpty && multiEmpty;
}

function referenceHasMore(ref) {
  let prezzi = [];
  try { prezzi = JSON.parse(ref.prezzi_json || '[]'); } catch (e) {}
  const hasVariants = prezzi.length > 1 && prezzi.some(p => p.variante);
  const hasOptions = (ref.options_json || '{}').trim() !== '{}';
  const hasMulti = (ref.multi_options_json || '{}').trim() !== '{}';
  return hasVariants || hasOptions || hasMulti;
}

// Analizza un prodotto e ritorna cosa va ripristinato (o null se è a posto)
function diagnose(p, ref) {
  const missingCategory = !p.category_id || String(p.category_id).trim() === '';
  const missingOptions = looksWiped(p) && referenceHasMore(ref);
  if (!missingCategory && !missingOptions) return null;
  return { missingCategory, missingOptions };
}

export async function onRequestGet(context) {
  const { env, request } = context;
  const secret = env.ADMIN_TOKEN_SECRET || 'default-dev-secret-change-in-prod';
  if (!(await verifySession(request, secret))) {
    return new Response(JSON.stringify({ error: 'Non autorizzato' }), { status: 401, headers: cors });
  }

  try {
    // I prodotti con categoria NULL non compaiono più nel menu pubblico, quindi
    // qui NON si filtra per active/categoria: vanno controllati tutti.
    const products = await env.DB.prepare(
      'SELECT id, name, category_id, prezzi_json, options_json, multi_options_json FROM products WHERE active = 1'
    ).all();

    const refByName = new Map(REFERENCE.map(r => [r.name, r]));
    const candidates = [];
    for (const p of products.results) {
      const ref = refByName.get(p.name);
      if (!ref) continue;
      const diag = diagnose(p, ref);
      if (diag) candidates.push({ id: p.id, name: p.name, category_id: p.category_id, ref_category: ref.category_id, ...diag });
    }

    return new Response(JSON.stringify({
      ok: true,
      preview: true,
      count: candidates.length,
      products: candidates.map(c => ({
        id: c.id, name: c.name, category_id: c.category_id,
        problema: [c.missingCategory ? 'categoria mancante' : null, c.missingOptions ? 'formato/scelte azzerate' : null].filter(Boolean).join(' + '),
      })),
    }), { status: 200, headers: cors });
  } catch (err) {
    return new Response(JSON.stringify({ error: err.message }), { status: 500, headers: cors });
  }
}

export async function onRequestPost(context) {
  const { env, request } = context;
  const secret = env.ADMIN_TOKEN_SECRET || 'default-dev-secret-change-in-prod';
  if (!(await verifySession(request, secret))) {
    return new Response(JSON.stringify({ error: 'Non autorizzato' }), { status: 401, headers: cors });
  }

  try {
    const products = await env.DB.prepare(
      'SELECT id, name, category_id, prezzi_json, options_json, multi_options_json FROM products WHERE active = 1'
    ).all();

    const refByName = new Map(REFERENCE.map(r => [r.name, r]));
    const restored = [];
    const stmts = [];
    for (const p of products.results) {
      const ref = refByName.get(p.name);
      if (!ref) continue;
      const diag = diagnose(p, ref);
      if (!diag) continue;

      const newCategoryId = diag.missingCategory ? ref.category_id : p.category_id;
      if (diag.missingOptions) {
        stmts.push(env.DB.prepare(
          'UPDATE products SET category_id = ?, prezzi_json = ?, options_json = ?, multi_options_json = ?, mandatory_choice = ? WHERE id = ?'
        ).bind(newCategoryId, ref.prezzi_json, ref.options_json, ref.multi_options_json, ref.mandatory_choice ? 1 : 0, p.id));
      } else {
        stmts.push(env.DB.prepare('UPDATE products SET category_id = ? WHERE id = ?').bind(newCategoryId, p.id));
      }
      restored.push({
        id: p.id, name: p.name, category_id: newCategoryId,
        problema: [diag.missingCategory ? 'categoria mancante' : null, diag.missingOptions ? 'formato/scelte azzerate' : null].filter(Boolean).join(' + '),
      });
    }

    if (stmts.length > 0) await env.DB.batch(stmts);

    return new Response(JSON.stringify({ ok: true, restored_count: restored.length, restored }), { status: 200, headers: cors });
  } catch (err) {
    return new Response(JSON.stringify({ error: err.message }), { status: 500, headers: cors });
  }
}

export async function onRequestOptions() {
  return new Response(null, {
    status: 204,
    headers: {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type',
    },
  });
}
